mapper.select:
SELECT u.id, u.username, u.password, u.email, u.role, u.status, u.created_time, u.updated_time, COALESCE(SUM(br.fine_amount), 0.00) AS debt_amount FROM sys_user u LEFT JOIN borrow_record br ON br.user_id = u.id AND br.fine_amount > 0
AND u.username LIKE CONCAT('%', #{username}, '%')
AND u.email LIKE CONCAT('%', #{email}, '%')
AND u.role = #{role}
AND u.status = #{status}
GROUP BY u.id, u.username, u.password, u.email, u.role, u.status, u.created_time, u.updated_time ORDER BY u.id DESC LIMIT #{offset}, #{pageSize}

